import type { ZodRawShape } from 'zod';
import type { IvObject } from './ivObject';
import type { Request, Response, NextFunction } from 'express';
export type RequestSchema = {
    body?: IvObject<any> | ZodRawShape;
    query?: IvObject<any> | ZodRawShape;
    params?: IvObject<any> | ZodRawShape;
};
export type ValidationErrorHandler = (errors: string, req: Request, res: Response, next: NextFunction) => void;
export interface ValidationMiddlewareOptions {
    schema: IvObject<any> | RequestSchema;
    errorHandler?: ValidationErrorHandler;
    /** Suppress validation error logs while still emitting metrics */
    disableLogs?: boolean;
}
